--
-- Table structure for table `contest_votes`
--

DROP TABLE IF EXISTS `contest_votes`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `contest_votes` (
  `vote_id` bigint NOT NULL AUTO_INCREMENT COMMENT '콘테스트 투표 ID',
  `program_id` bigint NOT NULL COMMENT '프로그램 ID',
  `program_apply_id` bigint NOT NULL COMMENT '투표 대상 참가 ID',
  `user_id` bigint NOT NULL COMMENT '투표자 사용자 ID',
  `voted_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '투표일시',
  `status` enum('ACTIVE','CANCELLED') NOT NULL DEFAULT 'ACTIVE' COMMENT '투표 상태',
  `cancelled_at` datetime DEFAULT NULL COMMENT '취소일시',
  `active_flag` tinyint GENERATED ALWAYS AS ((case when (`status` = _utf8mb4'ACTIVE') then 1 else NULL end)) STORED COMMENT '활성 플래그',
  PRIMARY KEY (`vote_id`),
  UNIQUE KEY `uk_contest_votes_active` (`program_id`,`user_id`,`active_flag`),
  KEY `ix_contest_votes_program_id` (`program_id`),
  KEY `ix_contest_votes_program_apply_id` (`program_apply_id`),
  KEY `ix_contest_votes_user_id` (`user_id`),
  KEY `ix_contest_votes_program_status` (`program_id`,`status`),
  KEY `ix_contest_votes_user_status` (`user_id`,`status`),
  CONSTRAINT `fk_contest_votes_program` FOREIGN KEY (`program_id`) REFERENCES `event_program` (`program_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_contest_votes_program_apply` FOREIGN KEY (`program_apply_id`) REFERENCES `event_program_apply` (`program_apply_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_contest_votes_users` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `ck_contest_votes_cancelled_at` CHECK ((((`status` = _utf8mb4'ACTIVE') and (`cancelled_at` is null)) or ((`status` = _utf8mb4'CANCELLED') and (`cancelled_at` is not null))))
) ENGINE=InnoDB AUTO_INCREMENT=1596 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

