DROP TABLE IF EXISTS `event`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `event` (
  `event_id` bigint NOT NULL AUTO_INCREMENT COMMENT '행사 ID',
  `event_name` varchar(255) NOT NULL COMMENT '행사명',
  `description` varchar(1000) NOT NULL COMMENT '행사 설명',
  `start_at` datetime NOT NULL COMMENT '시작일시',
  `end_at` datetime NOT NULL COMMENT '종료일시',
  `location` varchar(255) DEFAULT NULL COMMENT '주소 / 장소',
  `status` enum('PLANNED','ONGOING','ENDED','CANCELLED') NOT NULL COMMENT '행사 상태',
  `round_no` int DEFAULT NULL COMMENT '회차',
  `image_url` longtext COMMENT '이벤트 이미지(base64/URL)',
  `base_fee` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '행사 기본 참가비(입장권/참가비)',
  `organizer` varchar(255) DEFAULT NULL COMMENT '주최 정보',
  `organizer_phone` varchar(30) DEFAULT NULL COMMENT '주최자 연락처',
  `organizer_email` varchar(255) DEFAULT NULL COMMENT '주최자 이메일',
  PRIMARY KEY (`event_id`)
) ENGINE=InnoDB AUTO_INCREMENT=20003 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
