--
-- Table structure for table `event_apply`
--

DROP TABLE IF EXISTS `event_apply`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `event_apply` (
  `apply_id` bigint NOT NULL AUTO_INCREMENT COMMENT '신청 ID',
  `user_id` bigint NOT NULL COMMENT '사용자 ID',
  `event_id` bigint NOT NULL COMMENT '행사 ID',
  `applied_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '신청일시',
  `status` enum('APPLIED','CANCELLED','APPROVED','REJECTED') NOT NULL COMMENT '신청 상태',
  `active_flag` tinyint GENERATED ALWAYS AS ((case when (`status` in (_utf8mb4'APPLIED',_utf8mb4'APPROVED')) then 1 else NULL end)) STORED COMMENT 'APPLIED/APPROVED 상태면 1, 아니면 NULL (활성 중복 방지용)',
  PRIMARY KEY (`apply_id`),
  UNIQUE KEY `uk_event_apply_active` (`event_id`,`user_id`,`active_flag`),
  KEY `ix_event_apply_user_id` (`user_id`),
  KEY `ix_event_apply_event_id` (`event_id`),
  CONSTRAINT `fk_event_apply_event` FOREIGN KEY (`event_id`) REFERENCES `event` (`event_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_event_apply_users` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1788 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
