--
-- Table structure for table `event_history`
--

DROP TABLE IF EXISTS `event_history`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `event_history` (
  `history_id` bigint NOT NULL AUTO_INCREMENT COMMENT '참여 이력 ID',
  `user_id` bigint NOT NULL COMMENT '사용자 ID',
  `event_id` bigint NOT NULL COMMENT '행사 ID',
  `program_id` bigint NOT NULL COMMENT '프로그램 ID',
  `joined_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '참여일시',
  PRIMARY KEY (`history_id`),
  KEY `ix_event_history_user_id` (`user_id`),
  KEY `ix_event_history_event_id` (`event_id`),
  KEY `ix_event_history_program_id` (`program_id`),
  CONSTRAINT `fk_event_history_event` FOREIGN KEY (`event_id`) REFERENCES `event` (`event_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_event_history_program` FOREIGN KEY (`program_id`) REFERENCES `event_program` (`program_id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_event_history_users` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1207 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

