--
-- Table structure for table `event_images`
--

DROP TABLE IF EXISTS `event_images`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `event_images` (
  `event_image_id` bigint NOT NULL AUTO_INCREMENT,
  `event_id` bigint NOT NULL,
  `original_url` varchar(500) NOT NULL,
  `thumb_url` varchar(500) DEFAULT NULL,
  `image_order` int NOT NULL DEFAULT '1',
  `mime_type` enum('jpeg','jpg','png','gif','webp','tiff','svg') DEFAULT NULL,
  `file_size` bigint DEFAULT NULL,
  `created_by_admin_id` bigint DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`event_image_id`),
  UNIQUE KEY `uk_event_images_event_order` (`event_id`,`image_order`),
  KEY `ix_event_images_event_id` (`event_id`),
  KEY `ix_event_images_admin_id` (`created_by_admin_id`),
  CONSTRAINT `fk_event_images_admin` FOREIGN KEY (`created_by_admin_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_event_images_event` FOREIGN KEY (`event_id`) REFERENCES `event` (`event_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=101 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

