INSERT INTO `event_program` VALUES (1,1,'SESSION','펫테크 신기술 소개','전문 수의사가 계절별 건강관리 포인트를 안내합니다. 예방접종, 기생충 관리, 피부 관리 등 실용적인 정보를 제공합니다.','2025-09-10 02:00:00','2025-09-10 04:00:00',5,'/uploads/program/program_0077.jpg','2025-09-04 10:00:00'),(2,1,'EXPERIENCE','수제 간식 만들기','장애물 코스를 반려견과 함께 도전합니다. 초보자도 즐길 수 있는 낮은 난이도의 체험 코스입니다.','2025-09-09 17:00:00','2025-09-09 18:00:00',1,'/uploads/program/program_0024.jpg','2025-09-04 10:00:00'),(3,1,'EXPERIENCE','반려견 요가 체험','천연 재료로 건강한 반려견 간식을 직접 만들어봅니다. 완성된 간식은 포장하여 가져갈 수 있습니다.','2025-09-10 02:00:00','2025-09-10 03:00:00',1,'/uploads/program/program_0034.jpg','2025-08-27 10:00:00'),(4,1,'CONTEST','수영 독 챔피언십','반려견과 보호자의 패션 센스를 뽐내는 무대입니다. 테마는 자유이며, 창의성과 반려견과의 조화를 심사합니다.','2025-09-11 08:00:00','2025-09-11 09:00:00',2,'/uploads/program/program_0170.jpg','2025-08-29 10:00:00'),(5,1,'SESSION','반려동물 구강관리 특강','전문 수의사가 계절별 건강관리 포인트를 안내합니다. 예방접종, 기생충 관리, 피부 관리 등 실용적인 정보를 제공합니다.','2025-09-10 20:00:00','2025-09-10 22:00:00',5,'/uploads/program/program_0173.jpg','2025-08-29 10:00:00'),(6,1,'EXPERIENCE','핸드메이드 목줄 만들기','전문 그루머의 가이드에 따라 직접 반려견 미용을 체험합니다. 기본 브러싱부터 발톱 관리까지 배울 수 있습니다.','2025-09-09 07:00:00','2025-09-09 08:00:00',1,'/uploads/program/program_0242.jpg','2025-08-28 10:00:00'),(7,2,'EXPERIENCE','셀프 그루밍 체험','장애물 코스를 반려견과 함께 도전합니다. 초보자도 즐길 수 있는 낮은 난이도의 체험 코스입니다.','2025-09-10 16:00:00','2025-09-10 17:00:00',10,'/uploads/program/program_0017.jpg','2025-09-05 10:00:00'),(8,2,'EXPERIENCE','반려견 수영 체험','전문 그루머의 가이드에 따라 직접 반려견 미용을 체험합니다. 기본 브러싱부터 발톱 관리까지 배울 수 있습니다.','2025-09-10 03:00:00','2025-09-10 05:00:00',10,'/uploads/program/program_0096.jpg','2025-08-26 10:00:00'),(9,2,'CONTEST','펫 포토제닉 대회','재미있는 기술을 선보이는 대회입니다. 악수, 구르기, 장애물 통과 등 자유 주제로 1분 이내 시연합니다.','2025-09-09 18:00:00','2025-09-09 20:00:00',11,'/uploads/program/program_0123.jpg','2025-09-03 10:00:00'),(10,2,'EXPERIENCE','반려견 요가 체험','장애물 코스를 반려견과 함께 도전합니다. 초보자도 즐길 수 있는 낮은 난이도의 체험 코스입니다.','2025-09-10 05:00:00','2025-09-10 07:00:00',10,'/uploads/program/program_0034.jpg','2025-09-03 10:00:00'),(