--
-- Table structure for table `event_program_apply`
--

DROP TABLE IF EXISTS `event_program_apply`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `event_program_apply` (
  `program_apply_id` bigint NOT NULL AUTO_INCREMENT COMMENT '프로그램 참가 ID',
  `program_id` bigint NOT NULL COMMENT '프로그램 ID',
  `user_id` bigint DEFAULT NULL COMMENT '사용자 ID (어드민 직접 등록 시 NULL)',
  `pet_id` bigint DEFAULT NULL COMMENT '참가 반려동물 ID',
  `image_url` varchar(1000) DEFAULT NULL COMMENT '참가 이미지 URL',
  `admin_pet_name` varchar(100) DEFAULT NULL COMMENT '어드민 직접 등록 시 반려동물 이름',
  `status` enum('APPLIED','WAITING','APPROVED','REJECTED','CANCELLED','CHECKED_IN') NOT NULL COMMENT '상태',
  `ticket_no` varchar(30) DEFAULT NULL COMMENT '현장 티켓번호(표시용)',
  `eta_min` int DEFAULT NULL COMMENT '예상 대기시간(분)',
  `notified_at` datetime DEFAULT NULL COMMENT '10분 전 알림 발송 시점',
  `checked_in_at` datetime DEFAULT NULL COMMENT '참여 확정(체크인) 시점',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '생성일시',
  `cancelled_at` datetime DEFAULT NULL COMMENT '취소일시',
  `active_flag` tinyint GENERATED ALWAYS AS ((case when (`status` in (_utf8mb4'APPLIED',_utf8mb4'WAITING',_utf8mb4'APPROVED')) then 1 else NULL end)) STORED COMMENT '활성 신청 플래그',
  PRIMARY KEY (`program_apply_id`),
  UNIQUE KEY `uk_event_program_apply_program_user_active` (`program_id`,`user_id`,`active_flag`),
  KEY `ix_event_program_apply_program_id` (`program_id`),
  KEY `ix_event_program_apply_user_id` (`user_id`),
  KEY `ix_event_program_apply_pet_id` (`pet_id`),
  KEY `ix_event_program_apply_checked_in_at` (`checked_in_at`),
  CONSTRAINT `fk_event_program_apply_pet` FOREIGN KEY (`pet_id`) REFERENCES `pet` (`pet_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_event_program_apply_program` FOREIGN KEY (`program_id`) REFERENCES `event_program` (`program_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `ck_event_program_apply_cancelled_at` CHECK ((((`status` = _utf8mb4'CANCELLED') and (`cancelled_at` is not null)) or ((`status` <> _utf8mb4'CANCELLED') and (`cancelled_at` is null))))
) ENGINE=InnoDB AUTO_INCREMENT=3952 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `event_program_apply`
--

