--
-- Table structure for table `files`
--

DROP TABLE IF EXISTS `files`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `files` (
  `file_id` bigint NOT NULL AUTO_INCREMENT COMMENT '파일 ID',
  `original_name` varchar(255) NOT NULL COMMENT '원본 파일명',
  `stored_name` varchar(255) NOT NULL COMMENT '유니크 파일명',
  `user_id` bigint NOT NULL COMMENT '업로더 사용자 ID',
  `post_id` bigint DEFAULT NULL COMMENT '게시글 ID',
  `notice_id` bigint DEFAULT NULL COMMENT '공지 ID',
  `deleted_at` datetime DEFAULT NULL COMMENT '삭제일시(soft delete)',
  `deleted_by` bigint DEFAULT NULL COMMENT '삭제한 사용자 ID',
  `delete_reason` varchar(255) DEFAULT NULL COMMENT '삭제 사유',
  `object_deleted_at` datetime DEFAULT NULL COMMENT '원본 객체 삭제일시(게시글/공지 삭제 시점 기록)',
  PRIMARY KEY (`file_id`),
  UNIQUE KEY `uk_files_stored_name` (`stored_name`),
  UNIQUE KEY `uk_files_post_id` (`post_id`),
  UNIQUE KEY `uk_files_notice_id` (`notice_id`),
  KEY `ix_files_post_id` (`post_id`),
  KEY `ix_files_notice_id` (`notice_id`),
  KEY `idx_files_post_id_deleted_at` (`post_id`,`deleted_at`),
  KEY `idx_files_notice_id_deleted_at` (`notice_id`,`deleted_at`),
  KEY `idx_files_deleted_at_object_deleted_at` (`deleted_at`,`object_deleted_at`),
  CONSTRAINT `fk_files_notices` FOREIGN KEY (`notice_id`) REFERENCES `notices` (`notice_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_files_posts` FOREIGN KEY (`post_id`) REFERENCES `posts` (`post_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

