--
-- Table structure for table `galleries`
--

DROP TABLE IF EXISTS `galleries`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `galleries` (
  `gallery_id` bigint NOT NULL AUTO_INCREMENT COMMENT '갤러리 ID',
  `event_id` bigint NOT NULL COMMENT '행사 ID',
  `user_id` bigint NOT NULL COMMENT '작성자 사용자 ID',
  `gallery_title` varchar(255) NOT NULL COMMENT '갤러리 제목',
  `gallery_description` varchar(1000) DEFAULT NULL COMMENT '갤러리 본문',
  `view_count` int DEFAULT NULL COMMENT '조회수',
  `thumbnail_image_id` bigint DEFAULT NULL COMMENT '대표 이미지 ID',
  `gallery_status` enum('PUBLIC','PRIVATE','BLINDED','DELETED') NOT NULL DEFAULT 'PUBLIC' COMMENT '갤러리 상태',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '작성일시',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`gallery_id`),
  KEY `ix_galleries_event_id` (`event_id`),
  KEY `ix_galleries_user_id` (`user_id`),
  KEY `ix_galleries_thumbnail_image_id` (`thumbnail_image_id`),
  CONSTRAINT `fk_galleries_event` FOREIGN KEY (`event_id`) REFERENCES `event` (`event_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_galleries_thumbnail_image` FOREIGN KEY (`thumbnail_image_id`) REFERENCES `gallery_images` (`image_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_galleries_users` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=28 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `galleries`
--

