--
-- Table structure for table `gallery_images`
--

DROP TABLE IF EXISTS `gallery_images`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `gallery_images` (
  `image_id` bigint NOT NULL AUTO_INCREMENT COMMENT '이미지 ID',
  `gallery_id` bigint NOT NULL COMMENT '갤러리 ID',
  `original_url` varchar(500) NOT NULL COMMENT '원본 이미지 경로',
  `thumb_url` varchar(500) DEFAULT NULL COMMENT '썸네일 이미지 경로',
  `image_order` int DEFAULT NULL COMMENT '이미지 정렬 순서',
  `mime_type` enum('jpeg','jpg','png','gif','webp','tiff','svg') DEFAULT NULL COMMENT '파일 타입',
  `file_size` int DEFAULT NULL COMMENT '파일 크기',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  PRIMARY KEY (`image_id`),
  KEY `ix_gallery_images_gallery_id` (`gallery_id`),
  CONSTRAINT `fk_gallery_images_gallery` FOREIGN KEY (`gallery_id`) REFERENCES `galleries` (`gallery_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=98 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

