--
-- Table structure for table `gallery_likes`
--

DROP TABLE IF EXISTS `gallery_likes`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `gallery_likes` (
  `like_id` bigint NOT NULL AUTO_INCREMENT COMMENT '좋아요 ID',
  `gallery_id` bigint NOT NULL COMMENT '갤러리 ID',
  `user_id` bigint NOT NULL COMMENT '사용자 ID',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '생성일시',
  PRIMARY KEY (`like_id`),
  UNIQUE KEY `uk_gallery_likes_gallery_user` (`gallery_id`,`user_id`),
  KEY `ix_gallery_likes_gallery_id` (`gallery_id`),
  KEY `ix_gallery_likes_user_id` (`user_id`),
  CONSTRAINT `fk_gallery_likes_gallery` FOREIGN KEY (`gallery_id`) REFERENCES `galleries` (`gallery_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_gallery_likes_users` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=281 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `gallery_likes`
--

LOCK TABLES `gallery_likes` WRITE;
/*!40000 ALTER TABLE `gallery_likes` DISABLE KEYS */;
