--
-- Table structure for table `inquiry_answers`
--

DROP TABLE IF EXISTS `inquiry_answers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `inquiry_answers` (
  `answer_id` bigint NOT NULL AUTO_INCREMENT COMMENT '답변 ID',
  `inquiry_id` bigint NOT NULL COMMENT '문의 ID',
  `admin_id` bigint NOT NULL COMMENT '관리자 ID',
  `content` text NOT NULL COMMENT '내용',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '작성일시',
  PRIMARY KEY (`answer_id`),
  KEY `ix_inquiry_answers_inquiry_id` (`inquiry_id`),
  KEY `ix_inquiry_answers_admin_id` (`admin_id`),
  CONSTRAINT `fk_inquiry_answers_admin_users` FOREIGN KEY (`admin_id`) REFERENCES `users` (`user_id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_inquiry_answers_inquiry` FOREIGN KEY (`inquiry_id`) REFERENCES `inquiries` (`inquiry_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `inquiry_answers`
--

LOCK TABLES `inquiry_answers` WRITE;
/*!40000 ALTER TABLE `inquiry_answers` DISABLE KEYS */;
INSERT INTO `inquiry_answers` VALUES (1,3,3,'안녕하세요, 결제 내역 확인 결과 중복 결제가 맞으며 자동 취소 처리 중입니다. 카카오페이 기준 1~3영업일 내 환불됩니다. 불편을 드려 죄송합니다.','2025-02-28 14:48:41'),(2,4,3,'안녕하세요! 결제 영수증 재발급은 마이페이지 > 결제내역에서 직접 다운로드 가능합니다. PDF 형식으로 제공되며, 추가 문의사항 있으시면 말씀해주세요.','2023-12-02 13:17:14'),(3,5,1,'안녕하세요, 행사 취소에 따른 환불은 결제하신 수단으로 자동 진행됩니다. 처리 기간은 카드결제 3~5영업일, 카카오페이 1~3영업일 소요됩니다.','2025-01-30 04:48:19'),(4,6,3,'안녕하세요! 프로그램 단위 부분 환불은 현재 시스템상 어렵습니다. 다만 해당 프로그램 취소 건에 한해 적립금으로 보상해드리고 있습니다. 자세한 사항은 개별 안내드리겠습니다.','2025-03-10 19:36:44'),(5,7,3,'안녕하세요, 닉네임 변경 오류 확인 결과 특수문자 포함 시 에러가 발생하는 버그를 확인했습니다. 현재 수정 중이며, 임시로 한글/영문/숫자만 사용해주시면 정상 작동합니다.','2023-04-15 18:43:49'),(6,8,1,'안녕하세요! 탈퇴 후 동일 이메일로 재가입은 30일 경과 후 가능합니다. 탈퇴 시 기존 활동내역(리뷰, 게시글 등)은 복구되지 않으니 신중하게 결정해주세요.','2023-06-04 19:18:54'),(7,9,3,'안녕하세요, 소셜 연동 해제는 마이페이지 > 계정설정 > 소셜 연동 관리에서 가능합니다. 기존 카카오 연동 해제 후 네이버 연동을 새로 추가해주시면 됩니다.','2025-07-05 14:32:53');
/*!40000 ALTER TABLE `inquiry_answers` ENABLE KEYS */;
