--
-- Table structure for table `notification`
--

DROP TABLE IF EXISTS `notification`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `notification` (
  `notification_id` bigint NOT NULL AUTO_INCREMENT COMMENT '알림ID',
  `type` enum('EVENT','NOTICE','PAYMENT','APPLY','SYSTEM') NOT NULL DEFAULT 'SYSTEM' COMMENT '알림 유형',
  `notification_title` varchar(255) NOT NULL COMMENT '제목',
  `content` varchar(255) NOT NULL COMMENT '내용',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '생성일시',
  PRIMARY KEY (`notification_id`)
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `notification`
--

LOCK TABLES `notification` WRITE;
/*!40000 ALTER TABLE `notification` DISABLE KEYS */;
INSERT INTO `notification` VALUES (1,'SYSTEM','푸푸에 오신 것을 환영합니다!','반려동물과 함께하는 특별한 경험, 푸푸에서 시작하세요.','2026-03-06 15:09:33'),(2,'EVENT','입장 QR코드가 발급되었습니다','마이페이지에서 QR코드를 확인해주세요.','2026-03-06 15:09:33'),(3,'NOTICE','새로운 공지사항이 등록되었습니다','중요한 안내사항을 확인해주세요.','2026-03-06 15:09:33'),(4,'PAYMENT','결제가 완료되었습니다','결제 내역은 마이페이지에서 확인할 수 있습니다.','2026-03-06 15:09:33'),(5,'APPLY','행사 신청이 승인되었습니다','행사 참가가 확정되었습니다. QR코드를 확인해주세요.','2026-03-06 15:09:33'),(6,'SYSTEM','비밀번호 변경 완료','비밀번호가 성공적으로 변경되었습니다.','2026-03-06 15:09:33'),(7,'EVENT','행사 시작 하루 전입니다!','내일 행사가 시작됩니다. 준비물을 확인해주세요.','2026-03-06 15:09:33'),(8,'PAYMENT','환불 처리가 완료되었습니다','환불 금액이 원래 결제 수단으로 반환됩니다.','2026-03-06 15:09:33'),(9,'APPLY','프로그램 참가 확정 안내','신청하신 프로그램 참가가 확정되었습니다.','2026-03-06 15:09:33'),(10,'SYSTEM','프로필 업데이트 완료','프로필 정보가 성공적으로 수정되었습니다.','2026-03-06 15:09:33'),(11,'EVENT','행사가 종료되었습니다','참가해주셔서 감사합니다. 후기를 남겨주세요!','2026-03-06 15:09:33'),(12,'NOTICE','서버 점검 완료 안내','예정된 서버 점검이 완료되었습니다. 정상 이용 가능합니다.','2026-03-06 15:09:33'),(13,'PAYMENT','결제 실패 안내','결제 처리 중 오류가 발생했습니다. 다시 시도해주세요.','2026-03-06 15:09:33'),(14,'APPLY','대기 순번 안내','현재 대기 순서가 되었습니다. 10분 내 입장해주세요.','2026-03-06 15:09:33'),(15,'SYSTEM','오랜만에 방문해주셨네요!','새로운 행사가 준비되어 있습니다. 확인해보세요.','2026-03-06 15:09:33'),(16,'SYSTEM','SMS','[POPUPS] 인증번호는 323653 입니다. (5분 이내 입력)','2026-03-06 16:11:37');
/*!40000 ALTER TABLE `notification` ENABLE KEYS */;
