--
-- Table structure for table `payment_transactions`
--

DROP TABLE IF EXISTS `payment_transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `payment_transactions` (
  `tx_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'PG 트랜잭션 ID',
  `payment_id` bigint NOT NULL COMMENT '결제 ID',
  `pg_provider` enum('KAKAOPAY') NOT NULL COMMENT 'PG 제공자',
  `pg_tid` varchar(100) NOT NULL COMMENT 'PG 거래ID',
  `pg_token` varchar(100) DEFAULT NULL COMMENT '승인 토큰',
  `status` enum('READY','APPROVED','CANCELLED','FAILED') NOT NULL DEFAULT 'READY' COMMENT '트랜잭션 상태',
  `idempotency_key` varchar(64) DEFAULT NULL COMMENT '멱등키',
  `raw_ready` json DEFAULT NULL COMMENT 'ready 원문 응답(JSON)',
  `raw_approve` json DEFAULT NULL COMMENT 'approve 원문 응답(JSON)',
  `raw_cancel` json DEFAULT NULL COMMENT 'cancel 원문 응답(JSON)',
  `requested_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '요청일시',
  `approved_at` datetime DEFAULT NULL COMMENT '승인일시',
  `cancelled_at` datetime DEFAULT NULL COMMENT '취소일시',
  `failed_at` datetime DEFAULT NULL COMMENT '실패일시',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '생성일시',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`tx_id`),
  UNIQUE KEY `uk_payment_transactions_payment_id` (`payment_id`),
  UNIQUE KEY `uk_payment_transactions_provider_tid` (`pg_provider`,`pg_tid`),
  KEY `ix_payment_transactions_status` (`status`),
  KEY `ix_payment_transactions_payment_id` (`payment_id`),
  CONSTRAINT `fk_payment_transactions_payment` FOREIGN KEY (`payment_id`) REFERENCES `payments` (`payment_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `ck_payment_transactions_status_datetime` CHECK ((((`status` = _utf8mb4'READY') and (`approved_at` is null) and (`cancelled_at` is null) and (`failed_at` is null)) or ((`status` = _utf8mb4'APPROVED') and (`approved_at` is not null) and (`cancelled_at` is null) and (`failed_at` is null)) or ((`status` = _utf8mb4'CANCELLED') and (`cancelled_at` is not null) and (`failed_at` is null)) or ((`status` = _utf8mb4'FAILED') and (`failed_at` is not null))))
) ENGINE=InnoDB AUTO_INCREMENT=975 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

