--
-- Table structure for table `pet`
--

DROP TABLE IF EXISTS `pet`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pet` (
  `pet_id` bigint NOT NULL AUTO_INCREMENT COMMENT '반려동물 ID',
  `user_id` bigint NOT NULL COMMENT '보호자 ID',
  `pet_name` varchar(100) DEFAULT NULL COMMENT '이름',
  `pet_breed` enum('DOG','CAT','OTHER') NOT NULL COMMENT '반려동물 종류',
  `pet_age` int DEFAULT NULL COMMENT '나이',
  `pet_weight` enum('XS','S','M','L','XL') DEFAULT NULL COMMENT '강아지 상세 분류(체중)',
  PRIMARY KEY (`pet_id`),
  KEY `ix_pet_user_id` (`user_id`),
  CONSTRAINT `fk_pet_users` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=113 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

