--
-- Table structure for table `posts`
--

DROP TABLE IF EXISTS `posts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `posts` (
  `post_id` bigint NOT NULL AUTO_INCREMENT COMMENT '게시글 ID',
  `board_id` bigint NOT NULL COMMENT '게시판 ID',
  `user_id` bigint NOT NULL COMMENT '사용자 ID',
  `post_title` varchar(255) NOT NULL COMMENT '제목',
  `content` text NOT NULL COMMENT '내용',
  `answer_content` text COMMENT '운영자 답변 내용(QnA용)',
  `answered_at` datetime DEFAULT NULL COMMENT '답변 작성/수정 일시',
  `file_attached` enum('Y','N') NOT NULL DEFAULT 'N' COMMENT '첨부파일 여부',
  `status` enum('DRAFT','PUBLISHED','HIDDEN') NOT NULL DEFAULT 'PUBLISHED' COMMENT '상태',
  `view_count` int NOT NULL DEFAULT '0' COMMENT '조회수',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '작성일시',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  `is_deleted` tinyint NOT NULL DEFAULT '0' COMMENT '삭제 여부',
  `is_comment_enabled` tinyint NOT NULL DEFAULT '1' COMMENT '댓글 사용 여부',
  PRIMARY KEY (`post_id`),
  KEY `ix_posts_board_id` (`board_id`),
  KEY `ix_posts_user_id` (`user_id`),
  KEY `ix_posts_status_created_at` (`status`,`created_at`),
  CONSTRAINT `fk_posts_boards` FOREIGN KEY (`board_id`) REFERENCES `boards` (`board_id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_posts_users` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=42 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `posts`
--

LOCK TABLES `posts` WRITE;
/*!40000 ALTER TABLE `posts` DISABLE KEYS */;
INSERT INTO `posts` VALUES (1,1,2,'오늘 산책하다가 생긴 일','오늘 아침 산책하다가 옆집 시바견이랑 만났는데, 우리 보리가 꼬리 흔들면서 엄청 좋아하더라고요. 매일 아침 만나니까 서로 친구가 된 것 같아요. 날씨도 좋고 기분 좋은 하루의 시작이었습니다.',NULL,NULL,'N','PUBLISHED',177,'2023-08-09 19:36:14','2023-08-09 19:36:14',0,1),(2,1,64,'우리 강아지가 처음으로 수영을 했어요','강아지 수영장이 근처에 생겨서 처음 데려갔는데, 처음엔 무서워하더니 금방 적응해서 신나게 놀았어요! 수영이 관절에도 좋다고 해서 앞으로 주 1회는 가려고요.',NULL,NULL,'Y','PUBLISHED',619,'2023-12-16 10:08:02','2023-12-16 10:08:02',0,1),(3,1,64,'반려견 친구를 소개합니다','저희 코코 소개합니다! 골든리트리버 3살이고, 세상에서 산책을 제일 좋아해요. 하루에 두 번 산책은 필수이고, 공놀이를 정말 좋아합니다. 반려견 친구 만들고 싶어요!',NULL,NULL,'N','PUBLISHED',150,'2024-04-11 12:22:52','2024-04-11 12:22:52',0,1),(4,1,79,'간식 숨기기 놀이 추천해요','간식 숨기기 놀이해봤는데 우리 애가 너무 잘 찾아요ㅋㅋ 처음엔 쉬운 데 숨겼다가 점점 난이도 올려봤는데, 코가 정말 예민한 게 느껴지더라고요. 두뇌 발달에도 좋다고 하니 추천합니다!',NULL,NULL,'N','PUBLISHED',130,'2024-01-17 02:42:45','2024-01-17 02:42:45',0,1),(5,1,99,'펫카페 가봤는데 후기 남겨요','주말에 판교 쪽 펫카페 다녀왔어요. 실내가 넓고 소형견 구역이랑 대형견 구역이 나뉘어 있어서 좋았어요. 음료 가격도 합리적이고 강아지 메뉴도 있더라고요. 이름은 나중에 올릴게요!',NULL,NULL,'Y','PUBLISHED',156,'2025-07-28 22:59:16','2026-03-06 21:14:29',0,1),(6,1,4,'강아지 잠자는 자세가 웃겨요','우리 댕댕이가 잘 때 배를 하늘로 향하고 자는데, 처음 봤을 때 깜짝 놀랐어요. 찾아보니까 편안하다는 뜻이라고 하네요. 사진 찍어뒀는데 너무 귀여워서 공유합니다.',NULL,NULL,'Y','PUBLISHED',781,'2024-10-12 19:17:56','2026-03-06 17:23:25',0,1),(7,1,23,'산책 중 만난 귀여운 강아지들','오늘 산책하면서 아기 비숑, 말티즈, 시바견 만났는데 다들 너무 귀여웠어요. 우리 애도 다른 강아지들이랑 잘 놀아서 다행이에요. 사회화가 정말 중요한 것 같습니다.',NULL,NULL,'Y','PUBLISHED',271,'2023-07-08 04:40:27','2023-07-08 04:40:27',0,1),(8,1,6,'우리집 댕댕이 생일파티 했어요','어제 보리 생일이라 강아지 전용 케이크 만들어줬어요! 고구마랑 닭가슴살로 만들었는데 진짜 맛있게 먹더라고요. 레시피 궁금하신 분 댓글 달아주시면 공유할게요.',NULL,NULL,'N','PUBLISHED',403,'2025-01-23 14:20:13','2026-03-06 16:02:36',0,1),(9,1,77,'비 오는 날 실내 놀이 뭐가 좋을까요','비 오는 날은 산책을 못 가니 실내 놀이가 중요한데요. 저는 노즈워크 매트 사용하고 있어요. 간식 숨겨놓으면 한참 동안 집중해서 찾더라고요. 다른 추천 있으신 분?',NULL,NULL,'Y','PUBLISHED',642,'2023-05-19 05:02:05','2023-05-19 05:02:05',0,1),(10,1,85,'처음으로 강아지옷을 사줬어요','처음으로 강아지 옷을 사줬는데 입히는 게 보통일이 아니에요ㅋㅋ 겨우 입혔는데 움직이질 않더라고요. 적응하는 데 시간이 좀 걸리는 것 같아요. 팁 있으시면 알려주세요!',NULL,NULL,'N','PUBLISHED',193,'2023-06-01 10:10:03','2023-06-01 10:10:03',0,1),(11,1,44,'애견카페에서 생긴 에피소드','어제 애견카페에서 우리 뭉치가 다른 강아지 간식을 뺏어먹는 대참사가ㅋㅋ 주인분한테 죄송하다고 사과하고 간식도 새로 사드렸어요. 다음부턴 조심해야겠어요.',NULL,NULL,'Y','PUBLISHED',75,'2023-06-04 09:38:39','2023-06-04 09:38:39',0,1),(12,1,11,'반려견과 함께 캠핑 다녀왔어요','가평 캠핑장 다녀왔는데 반려견 동반 가능해서 너무 좋았어요. 자연 속에서 뛰놀더니 밤에 바로 골아떨어지더라고요. 캠핑 갈 때 준비물 리스트 공유드려요.',NULL,NULL,'Y','PUBLISHED',741,'2025-02-11 15:45:18','2026-03-06 16:02:33',0,1),(13,1,39,'오늘의 간식 만들기 성공기','고구마 간식 만들기 성공했어요! 고구마 삶아서 얇게 썰고 오븐에 말렸는데, 시중에 파는 것보다 더 잘 먹어요. 첨가물 걱정 없어서 좋고요.',NULL,NULL,'N','PUBLISHED',748,'2025-04-07 07:03:58','2026-03-06 16:20:56',0,1),(14,1,14,'강아지랑 첫 여행 다녀온 후기','속초로 1박 2일 여행 갔는데, 펫 동반 펜션이라 편했어요. 해변 산책도 하고 맛있는 것도 먹고. 반려견 동반 여행지 추천 받습니다!',NULL,NULL,'N','PUBLISHED',414,'2025-03-16 23:09:38','2026-03-06 17:23:14',0,1),(15,1,39,'산책로 추천합니다 (서울 한강)','한강 이촌지구 산책로 추천해요. 자전거 도로랑 산책로가 분리되어 있어서 안전하고, 잔디밭도 넓어서 뛰놀기 좋아요. 주차도 편합니다.',NULL,NULL,'N','PUBLISHED',461,'2025-07-19 01:20:06','2026-03-06 16:02:30',0,1),(16,2,81,'강아지 예방접종 스케줄 총정리','강아지 예방접종은 생후 6~8주부터 시작해요. 종합백신(DHPPL)은 2~3주 간격으로 3~4회 접종하고, 광견병은 3개월령 이후에 접종합니다. 이후 매년 추가접종이 필요해요. 병원마다 스케줄이 약간 다를 수 있으니 담당 수의사와 상담해보세요.',NULL,NULL,'N','PUBLISHED',1918,'2025-04-07 17:28:15','2025-04-07 17:28:15',0,1),(17,2,73,'반려견 슬개골 탈구 증상과 예방법','슬개골 탈구는 소형견에게 흔한 질환입니다. 뒷다리를 절거나, 가끔 다리를 들고 걷거나, 앉을 때 다리를 옆으로 뻗는 증상이 있으면 의심해보세요. 체중 관리와 미끄러운 바닥 방지가 예방에 도움됩니다.',NULL,NULL,'N','PUBLISHED',884,'2025-10-11 22:47:57','2026-03-06 17:23:27',0,1),(18,2,27,'여름철 반려견 열사병 응급처치 방법','여름 산책 시 지면 온도 체크가 중요합니다. 손등을 5초 이상 지면에 대봤을 때 뜨거우면 산책을 미루세요. 열사병 증상으로는 과도한 헐떡임, 침 흘림, 구토, 비틀거림이 있으며, 발견 시 시원한 곳으로 이동 후 서서히 체온을 낮춰주세요.',NULL,NULL,'Y','PUBLISHED',384,'2023-10-18 03:13:12','2023-10-18 03:13:12',0,1),(19,2,37,'펫보험 비교 분석 (2025년 기준)','2025년 기준 주요 펫보험 비교해봤습니다. DB손보의 펫블리, KB손보의 펫원, 삼성화재의 펫사랑 세 가지를 비교했어요. 보장 범위, 자기부담금, 보험료, 면책기간이 모두 다르니 꼼꼼히 비교하시길 추천합니다.',NULL,NULL,'Y','PUBLISHED',967,'2023-08-27 00:13:19','2023-08-27 00:13:19',0,1),(20,2,93,'강아지 치아 관리 완벽 가이드','강아지 치아 관리 방법 정리합니다. 매일 전용 칫솔과 치약으로 양치해주는 것이 가장 좋고, 거부하면 덴탈 츄나 덴탈 토이부터 시작하세요. 1년에 1회 스케일링도 고려해보시고, 치석이 심하면 발치가 필요할 수 있습니다.',NULL,NULL,'Y','PUBLISHED',102,'2025-12-25 12:54:09','2026-03-06 16:16:58',0,1),(21,2,45,'반려견 사료 성분표 읽는 법','사료 뒷면 성분표 읽는 법입니다. 원재료는 함량 순으로 표기됩니다. 1~2번째에 육류가 있는 것이 좋고, 부산물(by-product)이나 곡물이 앞에 있는 건 피하세요. 조단백, 조지방, 조섬유 함량도 확인해보세요.',NULL,NULL,'Y','PUBLISHED',1162,'2024-09-05 13:23:38','2024-09-05 13:23:38',0,1),(22,2,97,'BARF 생식 급여 가이드 총정리','BARF 생식 급여를 6개월째 하고 있는데 경험 공유합니다. 처음엔 변이 무르다가 2주 정도 지나니 안정됐어요. 닭 등뼈, 소고기, 야채류를 7:2:1 비율로 급여하고 있습니다. 시작 전 수의사 상담은 필수입니다.',NULL,NULL,'N','PUBLISHED',1975,'2023-10-03 15:56:07','2023-10-03 15:56:07',0,1),(23,2,36,'강아지 분리불안 해결 5단계','분리불안 해결 5단계 공유합니다. 1단계: 짧은 외출부터 시작 2단계: 외출 전 과도한 인사 자제 3단계: 안전한 공간 마련 4단계: 놀이와 운동으로 에너지 발산 5단계: 심한 경우 전문가 상담. 저는 3개월 정도 걸렸어요.',NULL,NULL,'Y','PUBLISHED',1398,'2025-09-20 14:27:46','2026-03-06 17:23:44',0,1),(24,4,74,'강아지가 갑자기 밥을 안 먹어요','3살 비숑인데 갑자기 사료를 안 먹어요. 간식은 먹는데 밥만 거부합니다. 2일째인데 병원 가봐야 할까요? 최근에 달라진 건 없는 것 같은데...','안녕하세요! 2일 이상 밥을 거부한다면 동물병원 방문을 권장합니다. 간식만 먹는 경우 사료 기호성 문제일 수 있어요. 사료를 살짝 데워보시거나 습식 사료를 섞어보세요.','2023-11-04 12:27:34','Y','PUBLISHED',132,'2023-11-04 03:27:34','2023-11-04 03:27:34',0,1),(25,4,40,'발바닥이 갈라졌는데 어떻게 하나요','산책을 많이 하는 편인데 최근에 발바닥이 갈라져 있는 걸 발견했어요. 발밤 바르고 있는데 잘 낫지 않네요. 동물병원에서 치료받아야 하는 수준인지 궁금합니다.','발바닥 갈라짐은 건조한 계절에 흔한 증상이에요. 반려견 전용 발밤을 하루 2-3회 바르시고, 일주일 이상 지속되면 동물병원에서 확인받으시는 게 좋습니다.','2024-10-04 04:42:17','N','PUBLISHED',846,'2024-10-02 19:42:17','2026-03-06 16:20:03',0,1),(26,4,99,'분리불안이 심한 것 같은데 어떡하죠','출근할 때마다 짖고 문을 긁어요. 이웃한테 민원도 들어왔는데... 분리불안 교정은 어떻게 해야 하나요? 전문 훈련사를 찾아야 할까요?','분리불안은 단계적으로 접근해야 합니다. 짧은 시간(5분)부터 혼자 두는 연습을 하시고, 외출 전후 과도한 반응을 자제해주세요. 심한 경우 행동 전문 훈련사 상담을 추천드립니다.','2025-01-15 20:00:44','N','PUBLISHED',955,'2025-01-14 16:00:44','2026-03-06 16:20:30',0,1),(27,4,12,'사료 교체 기간은 어느 정도가 좋나요','현재 급여중인 사료에서 다른 브랜드로 바꾸려는데, 일주일 정도 서서히 섞어주면 될까요? 아니면 더 오래 걸리나요?',NULL,NULL,'N','PUBLISHED',170,'2025-10-24 22:40:28','2026-03-07 03:52:17',0,1),(28,4,39,'강아지 구토가 계속되는데 병원 가야하나요','어제부터 구토를 3번 했어요. 노란 거품 같은 게 나오는데 밥은 조금씩 먹어요. 내일까지 지켜봐도 될까요 아니면 바로 병원 가야하나요?','24시간 내 3회 이상 구토하면 바로 동물병원에 가시는 것이 좋습니다. 노란 거품은 공복 구토일 수 있지만, 다른 증상(설사, 무기력 등)이 동반되면 긴급합니다.','2025-09-24 00:52:28','Y','PUBLISHED',136,'2025-09-23 21:52:28','2026-03-07 04:02:34',0,1),(29,4,69,'산책 중 다른 강아지를 보면 짖어요','2살 진돗개인데 산책 중 다른 강아지를 보면 무조건 짖어요. 공격성은 아닌 것 같고 흥분해서 그러는 것 같은데, 교정 방법이 있을까요?','흥분성 짖음은 주의전환 훈련이 효과적입니다. 다른 강아지를 보는 순간 이름을 불러 시선을 돌리고, 조용히 있으면 바로 보상해주세요. 꾸준한 반복이 중요합니다.','2023-06-30 22:25:05','N','PUBLISHED',490,'2023-06-30 14:25:05','2023-06-30 14:25:05',0,1),(30,4,62,'체중이 갑자기 늘었는데 다이어트 방법 있나요','1년 사이에 2kg이 늘었어요. 수의사선생님이 비만이라고 하시는데 다이어트 사료가 효과 있나요? 간식을 줄이는 게 우선일까요?','수의사 진단대로 체중 관리가 필요하시네요. 급여량을 10-15% 줄이고, 간식을 줄이는 것부터 시작하세요. 저칼로리 간식(오이, 당근)으로 대체하시면 좋습니다.','2024-08-20 08:18:03','Y','PUBLISHED',920,'2024-08-19 00:18:03','2024-08-19 00:18:03',0,1),(31,4,67,'발톱 깎을 때 피가 나면 어떻게 하나요','집에서 발톱 깎다가 출혈이 생겼어요. 일단 지혈 파우더로 멈추긴 했는데, 앞으로도 집에서 깎아도 되는 건지... 팁 좀 부탁드립니다.','발톱 출혈 시 지혈파우더나 밀가루를 눌러주시면 됩니다. 혈관 위치를 파악하기 어렵다면 조금씩 자르시고, 밝은 발톱은 혈관이 보이니 참고하세요.','2023-07-02 18:51:17','N','PUBLISHED',711,'2023-07-02 07:51:17','2023-07-02 07:51:17',0,1),(32,4,31,'강아지가 풀을 먹는데 괜찮은건가요','산책할 때마다 풀을 뜯어 먹어요. 소화 안 되는 것 같기도 하고 걱정인데 왜 그러는 건지, 말려야 하는 건지 모르겠어요.','풀 먹는 행동은 정상적일 수 있지만, 과도하면 위장 불편의 신호일 수 있어요. 구토가 동반되지 않으면 크게 걱정하지 않으셔도 되지만, 제초제가 뿌려진 잔디는 피해주세요.','2025-09-11 07:19:47','N','PUBLISHED',392,'2025-09-09 08:19:47','2026-03-06 16:20:42',0,1),(33,4,34,'입양한 강아지가 새 환경에 적응을 못해요','2주 전에 입양한 유기견인데 아직도 구석에만 있고 밥을 잘 안 먹어요. 적응 기간이 보통 얼마나 걸리나요? 어떻게 접근하면 좋을까요?','입양견의 적응 기간은 보통 2주~2개월입니다. 조용한 공간을 마련해주시고, 스스로 다가올 때까지 기다려주세요. 억지로 안거나 만지지 마시고, 간식으로 신뢰를 쌓아가시면 됩니다.','2024-08-17 19:39:53','N','PUBLISHED',482,'2024-08-17 07:39:53','2026-03-06 17:23:42',0,1),(34,5,1,'회원가입은 어떻게 하나요?','우측 상단의 회원가입 버튼을 눌러 이메일 또는 소셜 계정으로 가입할 수 있습니다.','회원가입 후 이메일 인증까지 완료해야 정상 이용이 가능합니다.','2025-03-01 10:00:00','N','PUBLISHED',146,'2025-02-28 09:00:00','2026-03-07 04:02:09',0,0),(35,5,1,'비밀번호를 잊어버렸어요.','로그인 화면의 비밀번호 찾기에서 재설정 링크를 받을 수 있습니다.','가입한 이메일로 발송된 링크는 30분 동안만 유효합니다.','2025-03-01 10:10:00','N','PUBLISHED',124,'2025-02-28 09:10:00','2026-03-07 04:02:33',0,0),(36,5,1,'행사 신청은 어디서 하나요?','행사 상세 페이지에서 프로그램 탭의 신청 버튼을 통해 접수할 수 있습니다.','정원이 마감된 프로그램은 대기 신청만 가능합니다.','2025-03-01 10:20:00','N','PUBLISHED',150,'2025-02-28 09:20:00','2026-03-06 16:20:35',0,0),(37,5,1,'신청 취소 및 환불 규정이 궁금해요.','마이페이지의 신청 내역에서 취소 요청이 가능합니다.','행사 시작 3일 전까지는 전액 환불, 이후에는 환불이 제한됩니다.','2025-03-01 10:30:00','N','PUBLISHED',101,'2025-02-28 09:30:00','2026-03-07 04:02:37',0,0),(38,5,1,'행사 장소에 반려동물 동반 가능한가요?','행사별 안내사항에서 반려동물 동반 가능 여부를 확인할 수 있습니다.','일부 행사장은 예방접종 확인서 제출이 필요합니다.','2025-03-01 10:40:00','N','PUBLISHED',206,'2025-02-28 09:40:00','2026-03-06 16:17:21',0,0),(39,5,1,'사진 및 파일 업로드가 안돼요.','이미지 용량이 크거나 확장자가 지원되지 않으면 업로드에 실패할 수 있습니다.','jpg, png, webp 형식과 문서 pdf를 지원하며 파일당 10MB까지 업로드 가능합니다.','2025-03-01 10:50:00','N','PUBLISHED',115,'2025-02-28 09:50:00','2026-03-06 16:20:39',0,0),(40,5,1,'게시글 신고는 어떻게 하나요?','각 게시글 우측 상단 메뉴에서 신고를 선택해 접수할 수 있습니다.','운영팀이 접수 순서대로 검토하며 처리 결과는 알림으로 전달됩니다.','2025-03-01 11:00:00','N','PUBLISHED',88,'2025-02-28 10:00:00','2025-03-01 11:00:00',0,0),(41,5,1,'운영시간과 고객센터 연락처를 알려주세요.','고객센터는 평일 09:00~18:00에 운영됩니다.','점심시간(12:00~13:00)에는 채팅 상담이 일시 중단됩니다.','2025-03-01 11:10:00','N','PUBLISHED',166,'2025-02-28 10:10:00','2026-03-06 18:05:58',0,0);
/*!40000 ALTER TABLE `posts` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `program_participation_stats`
--

DROP TABLE IF EXISTS `program_participation_stats`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `program_participation_stats` (
  `user_id` bigint NOT NULL COMMENT '사용자 ID',
  `program_id` bigint NOT NULL COMMENT '프로그램 ID',
  `participate_count` bigint NOT NULL DEFAULT '0' COMMENT '참여 횟수',
  `last_participated_at` datetime DEFAULT NULL COMMENT '마지막 참여 시각',
  PRIMARY KEY (`user_id`,`program_id`),
  KEY `ix_pps_user_id` (`user_id`),
