/*!40000 ALTER TABLE `review_comments` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `reviews`
--

DROP TABLE IF EXISTS `reviews`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `reviews` (
  `review_id` bigint NOT NULL AUTO_INCREMENT COMMENT '후기 ID',
  `event_id` bigint NOT NULL COMMENT '행사 ID',
  `user_id` bigint NOT NULL COMMENT '사용자 ID',
  `review_title` varchar(255) NOT NULL COMMENT '제목',
  `content` text NOT NULL COMMENT '내용',
  `rating` tinyint NOT NULL COMMENT '별점',
  `view_count` int NOT NULL DEFAULT '0' COMMENT '조회수',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '작성일시',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  `is_deleted` tinyint NOT NULL DEFAULT '0' COMMENT '삭제 여부',
  `is_comment_enabled` tinyint NOT NULL DEFAULT '0' COMMENT '댓글 허용 여부',
  `review_status` enum('PUBLIC','REPORTED','BLINDED','DELETED') NOT NULL DEFAULT 'PUBLIC' COMMENT '상태',
  PRIMARY KEY (`review_id`),
  UNIQUE KEY `uk_reviews_event_user` (`event_id`,`user_id`),
  KEY `ix_reviews_event_id` (`event_id`),
  KEY `ix_reviews_user_id` (`user_id`),
  KEY `ix_reviews_status` (`review_status`),
  CONSTRAINT `fk_reviews_event` FOREIGN KEY (`event_id`) REFERENCES `event` (`event_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_reviews_users` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `ck_reviews_delete_consistency` CHECK ((((`is_deleted` = 1) and (`review_status` = _utf8mb4'DELETED')) or ((`is_deleted` = 0) and (`review_status` <> _utf8mb4'DELETED')))),
  CONSTRAINT `ck_reviews_rating` CHECK ((`rating` between 1 and 5))
) ENGINE=InnoDB AUTO_INCREMENT=438 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `reviews`
--

LOCK TABLES `reviews` WRITE;
/*!40000 ALTER TABLE `reviews` DISABLE KEYS */;
INSERT INTO `reviews` VALUES (1,1,35,'생각보다 훨씬 좋았어요','반려견 키운 지 1년 됐는데 이런 행사는 처음이었어요. 같은 반려인분들과 이야기도 나누고, 새로운 용품도 알게 되고 정말 유익했습니다. 무엇보다 우리 애가 행복해하는 모습에 제가 더 즐거웠어요.',4,61,'2025-09-17 03:00:00','2025-09-17 03:00:00',0,1,'PUBLIC'),(2,1,61,'부스가 다양해서 좋았어요','세부적인 것까지 신경 쓴 느낌이었어요. 배변봉투 무료 제공, 급수대 배치, 긴급 수의사 대기 등 반려동물을 정말 배려한 행사라고 느꼈습니다. 운영진분들 고생 많으셨어요!',4,60,'2025-09-12 22:00:00','2025-09-12 22:00:00',0,1,'PUBLIC'),(3,1,50,'생각보다 훨씬 좋았어요','보통 낯가림이 심한 우리 콩이가 여기서는 꼬리 흔들며 다른 강아지들이랑 잘 놀더라고요! 환경이 편안해서 그런 것 같아요. 포토존에서 찍은 사진도 너무 이쁘고, 기념 발도장 찍기도 귀여웠어요.',4,298,'2025-09-13 22:00:00','2025-09-13 22:00:00',0,1,'PUBLIC'),(4,1,66,'부스가 다양해서 좋았어요','주차장이 부족해서 30분 넘게 헤맸어요... 결국 멀리 주차하고 걸어왔는데, 셔틀버스가 있었으면 좋겠어요. 그래도 행사 자체는 알차고 프로그램도 재밌어서 만족합니다.',4,280,'2025-09-12 06:00:00','2025-09-12 06:00:00',0,1,'PUBLIC'),(5,1,56,'우리 강아지가 제일 좋아한 행사','반려견 키운 지 1년 됐는데 이런 행사는 처음이었어요. 같은 반려인분들과 이야기도 나누고, 새로운 용품도 알게 되고 정말 유익했습니다. 무엇보다 우리 애가 행복해하는 모습에 제가 더 즐거웠어요.',5,47,'2025-09-13 18:00:00','2025-09-13 18:00:00',0,1,'PUBLIC'),(6,1,45,'첫 펫행사인데 감동이었어요','주차장이 부족해서 30분 넘게 헤맸어요... 결국 멀리 주차하고 걸어왔는데, 셔틀버스가 있었으면 좋겠어요. 그래도 행사 자체는 알차고 프로그램도 재밌어서 만족합니다.',5,164,'2025-09-12 11:00:00','2025-09-12 11:00:00',0,1,'PUBLIC'),(7,1,52,'부스가 다양해서 좋았어요','부스가 100개 가까이 있었는데 시식 부스, 체험 부스, 판매 부스 골고루 있어서 지루할 틈이 없었어요. 특히 수제 간식 부스에서 산 닭가슴살 져키를 우리 애가 엄청 좋아해요.',5,242,'2025-09-12 01:00:00','2025-09-12 01:00:00',0,1,'PUBLIC'),(8,1,51,'정말 잘 다녀왔습니다!','보통 낯가림이 심한 우리 콩이가 여기서는 꼬리 흔들며 다른 강아지들이랑 잘 놀더라고요! 환경이 편안해서 그런 것 같아요. 포토존에서 찍은 사진도 너무 이쁘고, 기념 발도장 찍기도 귀여웠어요.',4,226,'2025-09-11 22:00:00','2025-09-11 22:00:00',0,1,'PUBLIC'),(9,1,44,'우리 강아지가 제일 좋아한 행사','간식 부스 때문에 지갑이 텅텅ㅋㅋ 수제 간식, 유기농 사료 샘플, 각종 영양제까지... 원래 구경만 하려고 했는데 결국 양손 가득 들고 나왔습니다. 하지만 후회없어요!',3,149,'2025-09-16 10:00:00','2025-09-16 10:00:00',0,1,'PUBLIC'),(10,1,49,'아쉬운 점이 좀 있었어요','부스가 100개 가까이 있었는데 시식 부스, 체험 부스, 판매 부스 골고루 있어서 지루할 틈이 없었어요. 특히 수제 간식 부스에서 산 닭가슴살 져키를 우리 애가 엄청 좋아해요.',5,157,'2025-09-13 01:00:00','2025-09-13 01:00:00',0,1,'PUBLIC'),(11,2,72,'가족 나들이로 딱이에요','세부적인 것까지 신경 쓴 느낌이었어요. 배변봉투 무료 제공, 급수대