--
-- Table structure for table `signup_sessions`
--

DROP TABLE IF EXISTS `signup_sessions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `signup_sessions` (
  `signup_session_id` bigint NOT NULL AUTO_INCREMENT COMMENT '회원가입 세션 PK',
  `signup_key` varchar(36) NOT NULL COMMENT '외부 노출용 UUID',
  `signup_type` enum('EMAIL','SOCIAL') NOT NULL COMMENT '가입 타입',
  `social_provider` varchar(30) DEFAULT NULL COMMENT 'SOCIAL 제공자',
  `social_provider_uid` varchar(255) DEFAULT NULL COMMENT 'SOCIAL 제공자 UID',
  `email` varchar(255) DEFAULT NULL COMMENT 'EMAIL 가입 이메일',
  `password_hash` varchar(255) DEFAULT NULL COMMENT '비밀번호 해시',
  `nickname` varchar(30) NOT NULL COMMENT '닉네임',
  `phone` varchar(30) NOT NULL COMMENT '휴대폰 번호',
  `otp_status` enum('PENDING','VERIFIED','EXPIRED') NOT NULL DEFAULT 'PENDING' COMMENT 'OTP 상태',
  `otp_verified_at` datetime DEFAULT NULL COMMENT '인증 완료 시각',
  `otp_last_sent_at` datetime DEFAULT NULL COMMENT '마지막 발송 시각',
  `otp_code_hash` varchar(128) DEFAULT NULL COMMENT '코드 해시',
  `otp_expires_at` datetime DEFAULT NULL COMMENT '만료 시각',
  `otp_fail_count` int NOT NULL DEFAULT '0' COMMENT '실패 횟수',
  `otp_blocked_until` datetime DEFAULT NULL COMMENT '차단 종료 시각',
  `email_status` enum('PENDING','VERIFIED','NOT_REQUIRED') NOT NULL DEFAULT 'PENDING' COMMENT '이메일 인증 상태',
  `email_verified_at` datetime DEFAULT NULL COMMENT '이메일 인증 완료 시각',
  `email_code_hash` varchar(128) DEFAULT NULL COMMENT '이메일 인증코드 해시',
  `email_expires_at` datetime DEFAULT NULL COMMENT '이메일 인증코드 만료 시각',
  `email_last_sent_at` datetime DEFAULT NULL COMMENT '발송 시각',
  `email_fail_count` int NOT NULL DEFAULT '0' COMMENT '실패 횟수',
  `expires_at` datetime NOT NULL COMMENT '세션 만료',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '생성 시각',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정 시각',
  PRIMARY KEY (`signup_session_id`),
  UNIQUE KEY `uk_signup_sessions_signup_key` (`signup_key`),
  KEY `idx_signup_sessions_phone` (`phone`),
  KEY `idx_signup_sessions_email` (`email`),
  KEY `idx_signup_sessions_otp_last_sent_at` (`otp_last_sent_at`),
  KEY `idx_signup_sessions_expires_at` (`expires_at`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `signup_sessions`
--

