CREATE TABLE `speakers` (
  `speaker_id` bigint NOT NULL AUTO_INCREMENT COMMENT '연사 ID',
  `speaker_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '연사 이름',
  `speaker_bio` varchar(1000) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '연사 소개 및 상세 정보',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `speaker_email` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '연사 email',
  `speaker_phone` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '연사 전화번호',
  `speaker_image_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '연사 프로필 이미지 URL',
  `deleted_at` datetime DEFAULT NULL COMMENT '삭제일시(소프트삭제)',
  PRIMARY KEY (`speaker_id`),
  UNIQUE KEY `uk_speakers_email` (`speaker_email`),
